import { useState } from 'react';
import { RadioGroup, RadioGroupItem } from "@/components/ui/radio-group";
import { Label } from "@/components/ui/label";
import { Card, CardContent } from "@/components/ui/card";

interface ShippingOptionsProps {
  options: ShippingOption[];
  totalWeight: number;
  zone: ShippingZone;
  onSelect: (option: ShippingOption) => void;
}

const ShippingOptions = ({ options, totalWeight, zone, onSelect }: ShippingOptionsProps) => {
  const [selectedId, setSelectedId] = useState<string>(options[0]?.id || '');
  const [estimatedDate, setEstimatedDate] = useState<string>('');

  const handleSelect = (option: ShippingOption) => {
    setSelectedId(option.id);
    const cost = option.calculateCost(totalWeight, zone);
    const today = new Date();
    const minDelivery = new Date(today);
    minDelivery.setDate(today.getDate() + option.minDays);
    const maxDelivery = new Date(today);
    maxDelivery.setDate(today.getDate() + option.maxDays);
    const formatDate = (d: Date) => d.toLocaleDateString('fr-FR');
    setEstimatedDate(`${formatDate(minDelivery)} - ${formatDate(maxDelivery)}`);
    onSelect({ ...option, calculatedCost: cost });
  };

  return (
    <Card>
      <CardContent className="p-4">
        <h3 className="font-bold text-lg mb-3">Options de livraison</h3>
        <RadioGroup value={selectedId} onValueChange={(id) => {
          const opt = options.find(o => o.id === id);
          if (opt) handleSelect(opt);
        }}>
          {options.map(option => {
            const cost = option.calculateCost(totalWeight, zone);
            const isAvailable = option.availableZones.includes(zone);
            if (!isAvailable) return null;
            return (
              <div key={option.id} className="flex items-center justify-between border-b py-3">
                <div className="flex items-center gap-3">
                  <RadioGroupItem value={option.id} id={option.id} />
                  <Label htmlFor={option.id} className="font-medium">
                    {option.name}
                    <p className="text-xs text-gray-500">{option.description}</p>
                  </Label>
                </div>
                <div className="text-right">
                  <p className="font-bold text-green-600">{cost.toFixed(2)} €</p>
                  <p className="text-xs text-gray-400">J+{option.minDays} à J+{option.maxDays}</p>
                </div>
              </div>
            );
          })}
        </RadioGroup>
        {estimatedDate && (
          <div className="mt-4 p-3 bg-blue-50 rounded-lg text-sm">
            <i className="fas fa-calendar-alt mr-2"></i>
            Livraison estimée entre le <strong>{estimatedDate}</strong>
          </div>
        )}
      </CardContent>
    </Card>
  );
};

export default ShippingOptions;
