function addBusinessDays(startDate: Date, days: number, holidays: Date[]): Date {
  let result = new Date(startDate);
  let addedDays = 0;

  // Normaliser les jours fériés pour comparaison (ignorer l'heure)
  const holidayDates = holidays.map(h => new Date(h.getFullYear(), h.getMonth(), h.getDate()));

  while (addedDays < days) {
    result.setDate(result.getDate() + 1);
    const dayOfWeek = result.getDay();
    const isWeekend = dayOfWeek === 0 || dayOfWeek === 6; // Dimanche ou Samedi
    const isHoliday = holidayDates.some(h => 
      h.getDate() === result.getDate() && 
      h.getMonth() === result.getMonth() && 
      h.getFullYear() === result.getFullYear()
    );

    if (!isWeekend && !isHoliday) {
      addedDays++;
    }
  }
  return result;
}

// Exemple d'utilisation pour estimer la date de livraison
