function calculateShipping(cartTotal: number, totalWeight: number, promoCode?: string): number {
  // 1. Gratuité si panier > 100€
  if (cartTotal > 100) {
    return 0;
  }

  // 2. Calcul standard
  let shippingCost = 3.50; // Frais fixes de base

  // 3. Supplément poids si > 3kg
  if (totalWeight > 3) {
    const excessWeight = totalWeight - 3;
    shippingCost += excessWeight * 0.25;
  }

  // 4. Application du code promo (arrondi à 2 décimales)
  if (promoCode === 'LIVRAISON10') {
    shippingCost = Math.max(0, shippingCost - 1); // Ne pas descendre en dessous de 0
  }

  // Arrondi à 2 décimales
  return Math.round(shippingCost * 100) / 100;
}

// Tests
console.log(calculateShipping(105, 4.4, undefined)); // 0 (gratuit)
console.log(calculateShipping(95, 4.4, undefined));  // 3.85
console.log(calculateShipping(95, 4.4, 'LIVRAISON10')); // 2.85
console.log(calculateShipping(50, 2.5, undefined)); // 3.50 (pas de dépassement poids)
